import React, { useState, useEffect } from 'react';
import { getExperiences } from '../api';

const Experience = () => {
  const [experiences, setExperiences] = useState([]);
  const [loading, setLoading] = useState(true);

  // Load experiences from database
  useEffect(() => {
    loadExperiences();
  }, []);

  const loadExperiences = async () => {
    try {
      setLoading(true);
      const response = await getExperiences();
      setExperiences(response.data);
    } catch (error) {
      console.error('Error loading experiences:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <section className="relative z-10 py-16 px-6">
        <div className="max-w-6xl mx-auto text-center text-gray-400">
          <div className="flex justify-center items-center gap-2">
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse"></div>
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse delay-100"></div>
            <div className="w-4 h-4 bg-purple-500 rounded-full animate-pulse delay-200"></div>
          </div>
          <p className="mt-4">Loading experiences...</p>
        </div>
      </section>
    );
  }

  return (
    <section id="experience" className="relative z-10 py-16 px-6">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Journey</h2>

        <div className="space-y-6">
          {experiences.length === 0 ? (
            <div className="text-center text-gray-500 py-10">
              <p className="text-4xl mb-4">📭</p>
              <p>No experiences yet.</p>
            </div>
          ) : (
            experiences.map((exp) => (
              <div 
                key={exp._id} 
                className="glass-card rounded-2xl p-6 hover:border-purple-500/30 transition-all duration-300 hover:-translate-y-1"
              >
                <div className="flex flex-wrap justify-between items-start mb-2">
                  <h3 className="text-xl font-bold text-white">{exp.role}</h3>
                  <span className="text-purple-400 text-sm font-medium">{exp.period}</span>
                </div>
                <p className="text-gray-400 font-medium mb-2">{exp.company}</p>
                <p className="text-gray-500 text-sm leading-relaxed">{exp.description}</p>
              </div>
            ))
          )}
        </div>
      </div>
    </section>
  );
};

export default Experience;
